class Solution(object):
    def beautifulIndices(self, s, a, b, k):
        """
        :type s: str
        :type a: str
        :type b: str
        :type k: int
        :rtype: List[int]
        """
        def kmp_search(text, pattern):
            """Find all occurrences using KMP"""
            n, m = len(text), len(pattern)
            lps = [0] * m
            j = 0
            for i in range(1, m):
                while j > 0 and pattern[i] != pattern[j]:
                    j = lps[j - 1]
                if pattern[i] == pattern[j]:
                    j += 1
                lps[i] = j

            indices = []
            j = 0
            for i in range(n):
                while j > 0 and text[i] != pattern[j]:
                    j = lps[j - 1]
                if text[i] == pattern[j]:
                    j += 1
                if j == m:
                    indices.append(i - m + 1)
                    j = lps[j - 1]
            return indices

        a_indices = kmp_search(s, a)
        b_indices = kmp_search(s, b)

        result = []
        for i in a_indices:
            for j in b_indices:
                if abs(j - i) <= k:
                    result.append(i)
                    break

        return result
